class Solution {
public:
    int maxVowels(string s, int k) {
        int vowels = 0, maxVowels = 0;
        for (int i = 0; i < s.size(); ++i) {
            if (isVowel(s[i])) ++vowels;
            if (i >= k && isVowel(s[i - k])) --vowels;
            if (i >= k - 1) maxVowels = max(maxVowels, vowels);
        }
        return maxVowels;
    }
    bool isVowel(char c) {
        return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
    }
};
